interface Tool {
  name: string
  description: string

  execute(
    context: ToolUseContext,
    params: Record<string, unknown>
  ): Promise<ToolResult>
}

// 权限检查在任何工具执行前进行
async function executeToolWithPermission(
  tool: Tool,
  context: ToolUseContext,
  params: Record<string, unknown>
): Promise<ToolResult> {
  if (!await canUseTool(tool.name, context)) {
    return { error: 'Permission denied' }
  }
  return tool.execute(context, params)
}

// 技能定义：优化代码库代码质量
const qualityCheckSkill: Skill = {
  name: 'quality-check',
  description: 'Run comprehensive quality checks',

  async execute(context: SkillContext) {
    // 步骤1：格式检查
    await formatCode(context.cwd)
    // 步骤2：类型检查
    await typeCheck(context.cwd)
    // 步骤3：运行测试
    await runTests(context.cwd)
    // 步骤4：生成报告
    return generateQualityReport()
  }
}

